/* ============================================================================== */
/*   PROMO CODE SECTION (no hardcoded codes visible)                              */
/* ============================================================================== */

function PromoCodeSection({ mobile }) {
  const [promoCode, setPromoCode] = useState('')
  const [promoResult, setPromoResult] = useState(null)
  const [promoLoading, setPromoLoading] = useState(false)
  const [expanded, setExpanded] = useState(false)

  // Auto-expand if URL has a promo param
  useEffect(() => {
    const params = new URLSearchParams(window.location.search)
    const code = params.get('promo') || params.get('code')
    if (code) {
      setExpanded(true)
      setPromoCode(code.toUpperCase())
    }
  }, [])

  const handleValidate = () => {
    if (!promoCode.trim()) return
    setPromoLoading(true)
    // Dynamic import to avoid circular deps
    import('@/utils/platform').then(({ getApiBase }) => {
      fetch(`${getApiBase()}/billing/discount/validate`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ code: promoCode.trim().toUpperCase() }),
      })
        .then(r => r.json())
        .then(d => { setPromoResult(d); setPromoLoading(false) })
        .catch(() => { setPromoResult({ valid: false, error: 'Network error' }); setPromoLoading(false) })
    })
  }

  return (
    <section className={`${s.promoSection} ${mobile ? s.promoSectionMobile : ''}`}>
      {!expanded ? (
        <div style={{ textAlign: 'center' }}>
          <button
            onClick={() => setExpanded(true)}
            className={s.promoExpandBtn}
          >
            Have a promo code?
          </button>
        </div>
      ) : (
        <div className={`${s.promoCard} ${mobile ? s.promoCardMobile : ''}`}>
          <div className={s.promoTitle}>
            Enter your promo code
          </div>
          <div className={s.promoInputRow}>
            <input
              type="text"
              value={promoCode}
              onChange={e => { setPromoCode(e.target.value.toUpperCase()); setPromoResult(null) }}
              placeholder="Enter code"
              onKeyDown={e => { if (e.key === 'Enter') handleValidate() }}
              className={s.promoInput}
            />
            <button
              onClick={handleValidate}
              disabled={promoLoading || !promoCode.trim()}
              className={s.promoApplyBtn}
              style={{
                cursor: promoLoading ? 'wait' : 'pointer',
                opacity: promoLoading || !promoCode.trim() ? 0.5 : 1,
              }}
            >
              {promoLoading ? '...' : 'Apply'}
            </button>
          </div>
          {promoResult && (
            <div className={s.promoResult} style={{
              color: promoResult.valid ? T.green : T.red,
            }}>
              {promoResult.valid ? promoResult.savings_text : (promoResult.error || 'Invalid code')}
            </div>
          )}
        </div>
      )}
    </section>
  )
}
